Staff & Faculty Styling
.dept-header {
    margin-bottom: 25px;
    border-bottom: 2px solid #e2e8f0;
    padding-bottom: 10px;
}

.dept-header h3 {
    font-size: 22px;
    font-weight: 700;
    color: #1e3a5f;
    display: flex;
    align-items: center;
}

.dept-header h3 i {
    color: #00b4d8;
}

.faculty-card {
    background: #ffffff;
    border-radius: 15px;
    overflow: hidden;
    box-shadow: 0 4px 15px rgba(0,0,0,0.05);
    transition: all 0.3s ease;
    border: 1px solid #f1f5f9;
    height: 100%;
    display: flex;
    flex-direction: column;
}

.faculty-card:hover {
    transform: translateY(-5px);
    box-shadow: 0 12px 30px rgba(30, 58, 95, 0.1);
    border-color: #00b4d8;
}

.faculty-photo-wrapper {
    width: 100%;
    padding: 20px 20px 10px 20px;
    text-align: center;
    background: #f8fafc;
}

.faculty-photo {
    width: 140px;
    height: 180px;
    object-fit: cover;
    border-radius: 10px;
    border: 3px solid #ffffff;
    box-shadow: 0 5px 15px rgba(0,0,0,0.1);
}

.faculty-info {
    padding: 15px 20px 20px 20px;
    text-align: center;
}

.faculty-name {
    font-size: 18px;
    font-weight: 700;
    color: #1e3a5f;
    margin-bottom: 5px;
}

.faculty-designation {
    font-size: 14px;
    color: #64748b;
    font-weight: 600;
    margin-bottom: 10px;
}

.faculty-experience {
    font-size: 12px;
    color: #00b4d8;
    background: rgba(0, 180, 216, 0.1);
    padding: 4px 12px;
    border-radius: 20px;
    display: inline-block;
    font-weight: 700;
}

/* Modal Styling */
.faculty-modal-content {
    border-radius: 20px;
    overflow: hidden;
    border: none;
    box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.25);
}

.modal-photo-col {
    background: #0f172a;
    display: flex;
    align-items: center;
    justify-content: center;
    overflow: hidden;
}

.profile-modal-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    min-height: 400px;
}

.modal-faculty-name {
    font-weight: 800;
    color: #1e3a5f;
    font-size: 28px;
}

.faculty-detail-item label {
    display: block;
    font-size: 11px;
    text-transform: uppercase;
    letter-spacing: 1px;
    color: #94a3b8;
    font-weight: 700;
    margin-bottom: 2px;
}

.faculty-detail-item p {
    font-size: 15px;
    color: #1e293b;
    margin-bottom: 0;
    line-height: 1.5;
}


/* Card Hover Overlay */
.faculty-card {
    cursor: pointer;
    position: relative;
}

.view-profile-overlay {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(30, 58, 95, 0.8);
    color: #fff;
    display: flex;
    align-items: center;
    justify-content: center;
    opacity: 0;
    transition: all 0.3s ease;
    border-radius: 10px;
    font-weight: 600;
    font-size: 14px;
}

.faculty-photo-wrapper {
    position: relative;
}

.faculty-card:hover .view-profile-overlay {
    opacity: 1;
}

.faculty-card:hover .faculty-photo {
    transform: scale(1.05);
}

.faculty-photo {
    transition: transform 0.3s ease;
}
